pragma solidity ^0.8.20;

contract TeamVestingVault {
    address private immutable owner;
    mapping(address => uint256) public allocation;
    mapping(address => uint256) public releaseTime;
    mapping(address => uint256) public withdrawn;

    event InvestorAdded(address indexed investor, uint256 amount, uint256 unlockTime);
    event Withdrawal(address indexed investor, uint256 amount);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    function addInvestor(address investor, uint256 amount, uint256 unlockTime) public onlyOwner {
        require(investor != address(0), "Investor cannot be the zero address");
        require(amount > 0, "Amount must be greater than zero");
        require(unlockTime > block.timestamp, "Unlock time must be in the future");

        allocation[investor] = amount;
        releaseTime[investor] = unlockTime;

        emit InvestorAdded(investor, amount, unlockTime);
    }

    function withdraw() public {
        uint256 availableAmount = allocation[msg.sender];
        require(block.timestamp >= releaseTime[msg.sender], "Release time not reached");
        require(availableAmount > withdrawn[msg.sender], "No funds available to withdraw");

        uint256 amountToWithdraw = availableAmount - withdrawn[msg.sender];
        withdrawn[msg.sender] += amountToWithdraw;
        allocation[msg.sender] = 0; // Reset allocation to prevent re-use
        emit Withdrawal(msg.sender, amountToWithdraw);

        // Here you would typically transfer the tokens/ETH to the investor.
        // For example, if this is an ERC20 token contract, you would call transfer(msg.sender, amountToWithdraw).
    }
}
